#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define INF INT_MAX
#define MIN(a, b) ((a) < (b) ? (a) : (b))
typedef struct Edge {
    int to;
    int weight;
    struct Edge* next;
} Edge;
typedef struct Graph {
    int numNodes;
    int numEdges;
    Edge** adjList;
} Graph;
Graph* createGraph(int numNodes, int numEdges) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numNodes = numNodes;
    graph->numEdges = numEdges;
    graph->adjList = (Edge**) malloc(numNodes * sizeof(Edge*));
    for (int i = 0; i < numNodes; i++) {
        graph->adjList[i] = NULL;
    }
    return graph;
}
void addEdge(Graph* graph, int from, int to, int weight) {
    Edge* edge = (Edge*) malloc(sizeof(Edge));
    edge->to = to;
    edge->weight = weight;
    edge->next = graph->adjList[from];
    graph->adjList[from] = edge;
}
void dfs(Graph* graph, int node, int target, int* visited, int* pathLength, int* minPathLength) {
    visited[node] = 1;
    if (node == target) {
        if (*pathLength < *minPathLength) {
            *minPathLength = *pathLength;
        }
        visited[node] = 0;
        return;
    }
    Edge* edge = graph->adjList[node];
    while (edge != NULL) {
        if (!visited[edge->to]) {
            *pathLength += edge->weight;
            dfs(graph, edge->to, target, visited, pathLength, minPathLength);
            *pathLength -= edge->weight;
        }
        edge = edge->next;
    }
    visited[node] = 0;
}
int shortestAveragePath(Graph* graph, int start, int target) {
    int* visited = (int*) malloc(graph->numNodes * sizeof(int));
    int* pathLength = (int*) malloc(sizeof(int));
    int* minPathLength = (int*) malloc(sizeof(int));
    *pathLength = 0;
    *minPathLength = INF;
    dfs(graph, start, target, visited, pathLength, minPathLength);
    free(visited);
    free(pathLength);
    free(minPathLength);
    if (*minPathLength == INF) {
        return -1;
    }
    return *minPathLength;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Graph* graph = createGraph(N, M);
        for (int i = 0; i < M; i++) {
            int from, to, weight;
            scanf("%d %d %d", &from, &to, &weight);
            addEdge(graph, from - 1, to - 1, weight);
        }
        int start, target;
        scanf("%d %d", &start, &target);
        int result = shortestAveragePath(graph, start - 1, target - 1);
        printf("%d\n", result);
        free(graph->adjList);
        free(graph);
    }
    return 0;
}

