// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    static class Edge {
        int to;
        int weight;
        Edge(int to, int weight) {
            this.to = to;
            this.weight = weight;
        }
    }
    static class Graph {
        int numNodes;
        int numEdges;
        Edge[][] adjList;
        Graph(int numNodes, int numEdges) {
            this.numNodes = numNodes;
            this.numEdges = numEdges;
            adjList = new Edge[numNodes][];
            for (int i = 0; i < numNodes; i++) {
                adjList[i] = new Edge[0];
            }
        }
        void addEdge(int from, int to, int weight) {
            Edge[] newAdjList = new Edge[adjList[from].length + 1];
            System.arraycopy(adjList[from], 0, newAdjList, 0, adjList[from].length);
            newAdjList[adjList[from].length] = new Edge(to, weight);
            adjList[from] = newAdjList;
        }
    }
    static void dfs(Graph graph, int node, int target, boolean[] visited, int pathLength, int[] minPathLength) {
        visited[node] = true;
        if (node == target) {
            if (pathLength < minPathLength[0]) {
                minPathLength[0] = pathLength;
            }
            visited[node] = false;
            return;
        }
        for (Edge edge : graph.adjList[node]) {
            if (!visited[edge.to]) {
                dfs(graph, edge.to, target, visited, pathLength + edge.weight, minPathLength);
            }
        }
        visited[node] = false;
    }
    static int shortestAveragePath(Graph graph, int start, int target) {
        boolean[] visited = new boolean[graph.numNodes];
        int[] minPathLength = new int[] {Integer.MAX_VALUE};
        dfs(graph, start, target, visited, 0, minPathLength);
        if (minPathLength[0] == Integer.MAX_VALUE) {
            return -1;
        }
        return minPathLength[0];
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            Graph graph = new Graph(N, M);
            for (int i = 0; i < M; i++) {
                int from = scanner.nextInt() - 1;
                int to = scanner.nextInt() - 1;
                int weight = scanner.nextInt();
                graph.addEdge(from, to, weight);
            }
            int start = scanner.nextInt() - 1;
            int target = scanner.nextInt() - 1;
            int result = shortestAveragePath(graph, start, target);
            System.out.println(result);
        }
    }
}

