const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function readLine() {
    return input[idx++];
}
function readInt() {
    return parseInt(readLine());
}
function readInts() {
    return readLine().split(' ').map(Number);
}
function addEdge(graph, from, to, weight) {
    graph[from].push([to, weight]);
}
function dfs(graph, node, target, visited, pathLength, minPathLength) {
    visited[node] = true;
    if (node === target) {
        if (pathLength < minPathLength[0]) {
            minPathLength[0] = pathLength;
        }
        visited[node] = false;
        return;
    }
    for (const [to, weight] of graph[node]) {
        if (!visited[to]) {
            dfs(graph, to, target, visited, pathLength + weight, minPathLength);
        }
    }
    visited[node] = false;
}
function shortestAveragePath(graph, start, target) {
    const visited = new Array(graph.length).fill(false);
    const minPathLength = [Infinity];
    dfs(graph, start, target, visited, 0, minPathLength);
    if (minPathLength[0] === Infinity) {
        return -1;
    }
    return minPathLength[0];
}
function main() {
    const T = readInt();
    for (let i = 0; i < T; i++) {
        const [N, M] = readInts();
        const graph = new Array(N).fill(0).map(() => []);
        for (let j = 0; j < M; j++) {
            const [from, to, weight] = readInts();
            addEdge(graph, from - 1, to - 1, weight);
        }
        const [start, target] = readInts();
        const result = shortestAveragePath(graph, start - 1, target - 1);
        console.log(result);
    }
}
main();

